import { Alchemy, Network } from 'alchemy-sdk';
import { useEffect, useState } from 'react';

import './App.css';

// Refer to the README doc for more information about using API
// keys in client-side code. You should never do this in production
// level code.
const settings = {
  apiKey: process.env.REACT_APP_ALCHEMY_API_KEY,
  network: Network.ETH_MAINNET,
};


// In this week's lessons we used ethers.js. Here we are using the
// Alchemy SDK is an umbrella library with several different packages.
//
// You can read more about the packages here:
//   https://docs.alchemy.com/reference/alchemy-sdk-api-surface-overview#api-surface
const alchemy = new Alchemy(settings);

function App() {
  const [blockNumber, setBlockNumber] = useState();
  const [blockInfo, setBlockInfo] = useState();
  const [blockWithTxs, setBlockWithTxs] = useState();
  const [txReceipts, setTxReceipts] = useState([]);

  useEffect(() => {
    async function fetchData() {
      //Block number
      setBlockNumber(await alchemy.core.getBlockNumber());

      //Block info
      setBlockInfo(await alchemy.core.getBlock(number));

      //Block with full transaction objects
      const fullBlock = await alchemy.core.getBlockWithTransactions(number);
      setBlockWithTxs(fullBlock);

      //Fetch each transaction receipt
      const receipts = await Promise.all(
        fullBlock.transactions.slice(0, 10).map(
          (tx) => alchemy.core.getTransactionReceipt(tx.hash)
        )
      );
      setTxReceipts(receipts);
    }

    fetchData();
  }, []);

  return (
    <div className="App">
      <h2>Current Block: {blockNumber}</h2>

      {blockInfo && (
        <>
          <h3>Block Info</h3>
          <pre>{JSON.stringify(blockInfo, null, 2)}</pre>
        </>
      )}

      {blockWithTxs && (
        <>
          <h3>Transaction Hashes</h3>
          <ul>
            {blockWithTxs.transactions.map((tx) => (
              <li key={tx.hash}>{tx.hash}</li>
            ))}
          </ul>
        </>
      )}

      {txReceipts.length > 0 && (
        <>
          <h3>Sample Transaction Receipts (first 10)</h3>
          {txReceipts.map((receipt) => (
            <pre key={receipt.transactionHash}>
              {JSON.stringify(receipt, null, 2)}
            </pre>
          ))}
        </>
      )}
    </div>
  );}

export default App;
